import asyncio
import websockets
import json
import uuid
import collections
import time
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# --- Game State ---
# In-memory storage for simplicity. In a real MMO, this would be a database.
ITEMS = {
    "SWORD_COMMON": {"name": "Common Sword", "tradable": True},
    "SHIELD_WOOD": {"name": "Wooden Shield", "tradable": True},
    "POTION_HEALTH": {"name": "Health Potion", "tradable": True, "stackable": True},
    "RING_MAGIC": {"name": "Magic Ring", "tradable": True},
    "GOLD": {"name": "Gold Coin", "tradable": True, "stackable": True},
    "QUEST_ITEM_A": {"name": "Ancient Scroll", "tradable": False}
}

class ItemInstance:
    def __init__(self, item_id: str, quantity: int = 1, instance_id: str = None):
        if item_id not in ITEMS:
            raise ValueError(f"Invalid item_id: {item_id}")
        self.item_id = item_id
        self.instance_id = instance_id if instance_id else str(uuid.uuid4())
        self.quantity = quantity
        self.last_updated = time.time()

    def to_dict(self):
        return {
            "instance_id": self.instance_id,
            "item_id": self.item_id,
            "name": ITEMS[self.item_id]["name"],
            "quantity": self.quantity,
            "tradable": ITEMS[self.item_id]["tradable"],
            "stackable": ITEMS[self.item_id].get("stackable", False)
        }

class Player:
    def __init__(self, player_id: str):
        self.player_id = player_id
        # Inventory: instance_id -> ItemInstance
        self.inventory: dict[str, ItemInstance] = {}
        self.websocket = None
        self.is_online = False
        self.last_seen = time.time()
        self.trade_lock_expiration = 0 # Unix timestamp
        logging.info(f"Player {player_id} created.")

    def add_item(self, item_instance: ItemInstance):
        if ITEMS[item_instance.item_id].get("stackable", False):
            for existing_item_instance in self.inventory.values():
                if existing_item_instance.item_id == item_instance.item_id:
                    existing_item_instance.quantity += item_instance.quantity
                    existing_item_instance.last_updated = time.time()
                    logging.info(f"Player {self.player_id}: Stacked {item_instance.quantity}x {item_instance.item_id} onto existing.")
                    return existing_item_instance
        self.inventory[item_instance.instance_id] = item_instance
        item_instance.last_updated = time.time()
        logging.info(f"Player {self.player_id}: Added new item {item_instance.to_dict()}.")
        return item_instance

    def remove_item(self, instance_id: str, quantity: int = 1):
        if instance_id not in self.inventory:
            logging.warning(f"Player {self.player_id}: Attempted to remove non-existent item instance {instance_id}.")
            return None

        item_instance = self.inventory[instance_id]
        if item_instance.quantity < quantity:
            logging.warning(f"Player {self.player_id}: Attempted to remove {quantity}x {item_instance.item_id} but only {item_instance.quantity} exist for instance {instance_id}.")
            return None

        if item_instance.quantity == quantity:
            del self.inventory[instance_id]
            logging.info(f"Player {self.player_id}: Removed item instance {instance_id} ({item_instance.item_id}).")
            return item_instance
        else:
            item_instance.quantity -= quantity
            item_instance.last_updated = time.time()
            logging.info(f"Player {self.player_id}: Removed {quantity}x {item_instance.item_id} from stack {instance_id}. Remaining: {item_instance.quantity}.")
            # Return a copy representing the removed part for transfer
            removed_part = ItemInstance(item_instance.item_id, quantity=quantity, instance_id=str(uuid.uuid4()))
            return removed_part

    def get_item(self, instance_id: str):
        return self.inventory.get(instance_id)

    def to_public_dict(self):
        return {
            "player_id": self.player_id,
            "is_online": self.is_online,
            "trade_locked": self.trade_lock_expiration > time.time()
        }

# Global game state
PLAYERS: dict[str, Player] = {}
ACTIVE_CONNECTIONS: dict[str, Player] = {} # Websocket hash -> Player object

# --- Concurrency Control ---
PLAYER_LOCKS: dict[str, asyncio.Lock] = collections.defaultdict(asyncio.Lock)
ITEM_LOCKS: dict[str, asyncio.Lock] = collections.defaultdict(asyncio.Lock) # Lock per item instance


async def get_player(player_id: str) -> Player:
    """Retrieves or creates a player."""
    if player_id not in PLAYERS:
        # In a real game, this would load from a database
        player = Player(player_id)
        PLAYERS[player_id] = player
        # Give some initial items
        player.add_item(ItemInstance("SWORD_COMMON"))
        player.add_item(ItemInstance("POTION_HEALTH", quantity=3))
        player.add_item(ItemInstance("GOLD", quantity=100))
    return PLAYERS[player_id]

async def acquire_player_lock(player_id: str):
    """Acquires a lock for a player."""
    await PLAYER_LOCKS[player_id].acquire()
    logging.debug(f"Acquired player lock for {player_id}")

async def release_player_lock(player_id: str):
    """Releases a lock for a player."""
    PLAYER_LOCKS[player_id].release()
    logging.debug(f"Released player lock for {player_id}")

async def acquire_item_lock(item_instance_id: str):
    """Acquires a lock for a specific item instance."""
    await ITEM_LOCKS[item_instance_id].acquire()
    logging.debug(f"Acquired item lock for {item_instance_id}")

async def release_item_lock(item_instance_id: str):
    """Releases a lock for a specific item instance."""
    ITEM_LOCKS[item_instance_id].release()
    logging.debug(f"Released item lock for {item_instance_id}")

async def broadcast(message: dict):
    """Sends a message to all connected players."""
    if not message:
        return
    for player in ACTIVE_CONNECTIONS.values():
        if player.websocket and player.is_online:
            try:
                await player.websocket.send(json.dumps(message))
            except websockets.exceptions.ConnectionClosed:
                logging.warning(f"Failed to send broadcast to {player.player_id}: connection closed.")

async def send_to_player(player: Player, message: dict):
    """Sends a message to a specific player."""
    if not player or not player.websocket or not player.is_online:
        logging.warning(f"Attempted to send message to offline or invalid player: {player.player_id if player else 'N/A'}")
        return
    try:
        await player.websocket.send(json.dumps(message))
    except websockets.exceptions.ConnectionClosed:
        logging.warning(f"Failed to send message to {player.player_id}: connection closed.")

async def notify_inventory_change(player: Player):
    """Notifies a player about changes in their inventory."""
    if player.is_online:
        await send_to_player(player, {
            "type": "inventory_update",
            "inventory": [item.to_dict() for item in player.inventory.values()]
        })

async def notify_player_status_change(player: Player):
    """Notifies all players about a player's online status change."""
    await broadcast({
        "type": "player_status_update",
        "player_status": player.to_public_dict()
    })


# --- Game Logic: Item Trading ---

async def handle_trade_request(
    requester_player: Player,
    recipient_id: str,
    item_instance_id: str,
    quantity: int
):
    """
    Handles a request to trade an item from requester to recipient.
    This function implements concurrent safe item transfer.
    """
    if quantity <= 0:
        await send_to_player(requester_player, {"type": "error", "message": "Quantity must be positive."})
        return

    recipient_player = PLAYERS.get(recipient_id)
    if not recipient_player or not recipient_player.is_online:
        await send_to_player(requester_player, {"type": "error", "message": f"Player {recipient_id} not found or offline."})
        return

    # Acquire locks in a consistent order to prevent deadlocks (e.g., by player_id)
    # Sort player IDs to ensure consistent lock acquisition order
    player_ids = sorted([requester_player.player_id, recipient_id])

    # Locking strategy: Player locks + Item locks
    # 1. Lock both players involved to prevent concurrent trades involving them.
    # 2. Lock the specific item instance being transferred.

    acquired_locks = []
    try:
        for p_id in player_ids:
            await acquire_player_lock(p_id)
            acquired_locks.append(p_id)

        # Re-check item existence after acquiring player locks
        item_to_transfer = requester_player.get_item(item_instance_id)
        if not item_to_transfer:
            await send_to_player(requester_player, {"type": "error", "message": f"Item instance {item_instance_id} not found in your inventory."})
            return
        if not ITEMS[item_to_transfer.item_id]["tradable"]:
            await send_to_player(requester_player, {"type": "error", "message": f"Item {item_to_transfer.item_id} is not tradable."})
            return
        if item_to_transfer.quantity < quantity:
            await send_to_player(requester_player, {"type": "error", "message": f"You only have {item_to_transfer.quantity} of item {item_to_transfer.item_id} (instance {item_instance_id})."})
            return

        await acquire_item_lock(item_instance_id)
        # Note: We don't acquire item lock for the recipient's inventory because it's an 'add' operation,
        # which will either create a new instance (no conflict) or modify an existing one (recipient's player lock
        # prevents concurrent modifications to their inventory).
        acquired_locks.append(item_instance_id)

        # Perform the transfer
        removed_item_part = requester_player.remove_item(item_instance_id, quantity)
        if removed_item_part:
            recipient_player.add_item(removed_item_part) # This creates a new instance if not stackable
            logging.info(f"Trade successful: {requester_player.player_id} -> {recipient_id}: {quantity}x {removed_item_part.item_id} (new instance: {removed_item_part.instance_id}).")

            await send_to_player(requester_player, {"type": "trade_success", "message": f"Successfully traded {quantity}x {ITEMS[removed_item_part.item_id]['name']} to {recipient_id}."})
            await send_to_player(recipient_player, {"type": "trade_received", "message": f"Received {quantity}x {ITEMS[removed_item_part.item_id]['name']} from {requester_player.player_id}."})

            await notify_inventory_change(requester_player)
            await notify_inventory_change(recipient_player)
        else:
            await send_to_player(requester_player, {"type": "error", "message": "Trade failed due to an internal error or insufficient items (race condition detected)."})

    except Exception as e:
        logging.error(f"Error during trade between {requester_player.player_id} and {recipient_id}: {e}", exc_info=True)
        await send_to_player(requester_player, {"type": "error", "message": "An error occurred during trade."})
    finally:
        # Release locks in reverse order of acquisition for safety, or simply iterate through acquired_locks
        for lock_id in reversed(acquired_locks):
            if lock_id in PLAYER_LOCKS and PLAYER_LOCKS[lock_id].locked():
                release_player_lock(lock_id)
            elif lock_id in ITEM_LOCKS and ITEM_LOCKS[lock_id].locked():
                release_item_lock(lock_id)


# --- Websocket Server Handling ---

async def handle_client(websocket, path):
    """Handles a new client connection."""
    player_id = None
    player = None
    connection_hash = hash(websocket)

    try:
        # Initial handshake: client sends player_id
        message = await websocket.recv()
        data = json.loads(message)

        if data.get("type") == "authenticate" and "player_id" in data:
            player_id = data["player_id"]
            player = await get_player(player_id)

            if player.is_online:
                await websocket.send(json.dumps({"type": "error", "message": "Player already connected."}))
                raise ConnectionRefusedError(f"Player {player_id} already connected.")

            player.websocket = websocket
            player.is_online = True
            player.last_seen = time.time()
            ACTIVE_CONNECTIONS[connection_hash] = player
            logging.info(f"Player {player_id} connected.")

            await send_to_player(player, {"type": "authenticated", "player_id": player_id})
            await notify_inventory_change(player)
            await notify_player_status_change(player)
            await send_to_player(player, {
                "type": "online_players",
                "players": [p.to_public_dict() for p in PLAYERS.values() if p.is_online]
            })

        else:
            await websocket.send(json.dumps({"type": "error", "message": "Authentication required."}))
            raise ConnectionRefusedError("Authentication failed.")

        # Main message loop
        async for message in websocket:
            try:
                data = json.loads(message)
                msg_type = data.get("type")
                logging.debug(f"Received from {player_id}: {msg_type}")

                if msg_type == "request_inventory":
                    await notify_inventory_change(player)
                elif msg_type == "request_players":
                    await send_to_player(player, {
                        "type": "online_players",
                        "players": [p.to_public_dict() for p in PLAYERS.values() if p.is_online]
                    })
                elif msg_type == "trade_item":
                    recipient_id = data.get("recipient_id")
                    item_instance_id = data.get("item_instance_id")
                    quantity = data.get("quantity", 1)
                    if not all([recipient_id, item_instance_id]) or not isinstance(quantity, int):
                        await send_to_player(player, {"type": "error", "message": "Invalid trade request parameters."})
                        continue
                    await handle_trade_request(player, recipient_id, item_instance_id, quantity)
                else:
                    await send_to_player(player, {"type": "error", "message": f"Unknown message type: {msg_type}"})

            except json.JSONDecodeError:
                await send_to_player(player, {"type": "error", "message": "Invalid JSON."})
            except Exception as e:
                logging.error(f"Error processing message from {player_id}: {e}", exc_info=True)
                await send_to_player(player, {"type": "error", "message": f"Server error: {e}"})

    except websockets.exceptions.ConnectionClosedOK:
        logging.info(f"Client {player_id} disconnected gracefully.")
    except ConnectionRefusedError as e:
        logging.warning(f"Connection refused: {e}")
    except Exception as e:
        logging.error(f"Handler error for {player_id}: {e}", exc_info=True)
    finally:
        if player_id and connection_hash in ACTIVE_CONNECTIONS:
            # Only mark offline if this specific connection was the active one for the player
            if ACTIVE_CONNECTIONS[connection_hash] == player:
                player.is_online = False
                player.websocket = None
                player.last_seen = time.time()
                logging.info(f"Player {player_id} marked offline.")
                await notify_player_status_change(player)
            del ACTIVE_CONNECTIONS[connection_hash]


async def main():
    """Starts the websocket server."""
    port = 8765
    server = await websockets.serve(handle_client, "localhost", port)
    logging.info(f"MMO Game Server started on ws://localhost:{port}")
    await server.wait_closed()

if __name__ == "__main__":
    asyncio.run(main())

